    "challenges": [
      {
        "instruction": "Isikan tempat kosong berikut dengan istilah yang tepat berdasarkan Pengenalan kepada Bahan Pembinaan yang telah dipelajari. Rujuk kepada kad pembelajaran dan video untuk petunjuk.",
        "codeTemplate": "Bahan pembinaan seperti _____, _____, dan _____ adalah elemen asas dalam setiap projek pembinaan.",
        "options": [
          "kayu",
          "batu",
          "kaca",
          "logam",
          "konkrit"
        ],
        "correctAnswer": "kayu, batu, logam",
        "explanation": "Bahan pembinaan yang disebutkan adalah kayu, batu, dan logam, yang merupakan elemen asas dalam setiap projek pembinaan."
      },
      {
        "instruction": "Lengkapkan ayat berikut dengan istilah yang sesuai berdasarkan pengetahuan anda tentang kelebihan dan kekurangan bahan pembinaan.",
        "codeTemplate": "Kelebihan _____ adalah ia ringan dan mudah diproses, tetapi kekurangannya adalah _____ yang rendah.",
        "options": [
          "kayu",
          "batu",
          "konkrit",
          "logam"
        ],
        "correctAnswer": "kayu, ketahanan",
        "explanation": "Kelebihan kayu adalah ringan dan mudah diproses, tetapi kekurangannya adalah ketahanan yang rendah berbanding bahan lain."
      }
    ]
  }
}
